{
        "type": "object",
        "required": [
          "purchaseOrder"
        ],
        "properties": {
          "processInstanceId": {
            "type": "string",
            "description": "Unique BPMN process instance ID from UiPath Maestro. Used for traceability and correlation. Format: UUID or alphanumeric string. If not provided, generate a trace ID."
          },
          "invoiceFile": {
            "description": "Scanned or digital PDF invoice file uploaded as a job attachment. When provided, use the Analyze Files tool to extract all invoice data (invoice number, date, vendor, line items, amounts, bank details, PO reference) before reconciliation. Takes precedence over the structured invoice field if both are provided.",
            "$ref": "#/definitions/job-attachment"
          },
          "purchaseOrder": {
            "type": "object",
            "description": "The Purchase Order document as extracted by the RPA robot from the ERP system. Must include header and line-item details.",
            "required": [
              "poNumber",
              "vendorId",
              "vendorName",
              "currency",
              "totalAmount",
              "lineItems"
            ],
            "properties": {
              "poNumber": {
                "type": "string",
                "description": "Unique PO reference number from the ERP (e.g., PO-2026-00123)."
              },
              "vendorId": {
                "type": "string",
                "description": "Internal vendor master ID."
              },
              "vendorName": {
                "type": "string",
                "description": "Legal vendor name as registered in the ERP."
              },
              "orderDate": {
                "type": "string",
                "description": "PO creation date in ISO 8601 format (YYYY-MM-DD)."
              },
              "currency": {
                "type": "string",
                "description": "3-letter ISO 4217 currency code (e.g., USD, EUR, GBP)."
              },
              "totalAmount": {
                "type": "number",
                "description": "Total approved PO amount in the stated currency, excluding tax."
              },
              "taxAmount": {
                "type": "number",
                "description": "Tax amount on the PO, if applicable. Defaults to 0 if omitted."
              },
              "paymentTerms": {
                "type": "string",
                "description": "Payment terms code or description (e.g., NET30, 2/10-NET30)."
              },
              "costCenter": {
                "type": "string",
                "description": "Cost center or department code for GL coding."
              },
              "category": {
                "type": "string",
                "description": "Spend category (e.g., IT, Facilities, Marketing, Services, Goods). Used for approval routing rules."
              },
              "lineItems": {
                "type": "array",
                "description": "Individual PO line items. Each item represents an ordered SKU or service.",
                "items": {
                  "type": "object",
                  "required": [
                    "lineNumber",
                    "description",
                    "quantityOrdered",
                    "unitPrice",
                    "totalPrice"
                  ],
                  "properties": {
                    "lineNumber": {
                      "type": "integer",
                      "description": "Sequential line number starting from 1."
                    },
                    "itemCode": {
                      "type": "string",
                      "description": "SKU or service code."
                    },
                    "description": {
                      "type": "string",
                      "description": "Item or service description."
                    },
                    "quantityOrdered": {
                      "type": "number",
                      "description": "Quantity ordered."
                    },
                    "unitPrice": {
                      "type": "number",
                      "description": "Agreed unit price in PO currency."
                    },
                    "totalPrice": {
                      "type": "number",
                      "description": "quantityOrdered x unitPrice."
                    },
                    "glCode": {
                      "type": "string",
                      "description": "General ledger account code."
                    },
                    "deliveryDate": {
                      "type": "string",
                      "description": "Expected delivery date (YYYY-MM-DD)."
                    }
                  }
                }
              }
            }
          },
          "goodsReceiptNote": {
            "type": "object",
            "description": "Goods Receipt Note (GRN) confirming physical receipt of goods or service completion. May be absent for service-only POs \u2014 treat as fully received if omitted.",
            "properties": {
              "grnNumber": {
                "type": "string",
                "description": "Unique GRN reference number."
              },
              "receiptDate": {
                "type": "string",
                "description": "Date goods/services were received (YYYY-MM-DD)."
              },
              "receivedBy": {
                "type": "string",
                "description": "Name or employee ID of the receiver."
              },
              "lineItems": {
                "type": "array",
                "description": "Received line items. Match by lineNumber to PO.",
                "items": {
                  "type": "object",
                  "required": [
                    "lineNumber",
                    "quantityReceived"
                  ],
                  "properties": {
                    "lineNumber": {
                      "type": "integer",
                      "description": "PO line number this receipt corresponds to."
                    },
                    "itemCode": {
                      "type": "string",
                      "description": "SKU or service code."
                    },
                    "description": {
                      "type": "string",
                      "description": "Description of received item."
                    },
                    "quantityReceived": {
                      "type": "number",
                      "description": "Actual quantity received and accepted."
                    },
                    "condition": {
                      "type": "string",
                      "description": "Condition of received goods: GOOD, DAMAGED, PARTIAL, REJECTED."
                    }
                  }
                }
              }
            }
          },
          "invoice": {
            "type": "object",
            "description": "Vendor invoice as structured data extracted by RPA from email, portal, or EDI. Optional when invoiceFile is provided \u2014 the agent will extract invoice data from the PDF using Analyze Files instead. If both are present, invoiceFile takes precedence.",
            "properties": {
              "invoiceNumber": {
                "type": "string",
                "description": "Vendor-assigned invoice number."
              },
              "invoiceDate": {
                "type": "string",
                "description": "Invoice issue date (YYYY-MM-DD)."
              },
              "dueDate": {
                "type": "string",
                "description": "Payment due date (YYYY-MM-DD)."
              },
              "vendorId": {
                "type": "string",
                "description": "Vendor ID as stated on the invoice. Should match PO vendorId."
              },
              "poReference": {
                "type": "string",
                "description": "PO number referenced on the invoice. Should match purchaseOrder.poNumber."
              },
              "currency": {
                "type": "string",
                "description": "3-letter ISO 4217 currency code on the invoice."
              },
              "subtotalAmount": {
                "type": "number",
                "description": "Invoice subtotal before tax."
              },
              "taxAmount": {
                "type": "number",
                "description": "Tax charged on the invoice."
              },
              "totalAmount": {
                "type": "number",
                "description": "Total amount due including tax."
              },
              "paymentTerms": {
                "type": "string",
                "description": "Payment terms stated on the invoice."
              },
              "bankDetails": {
                "type": "object",
                "description": "Vendor bank details on invoice. Flag if they differ from ERP master \u2014 could indicate fraud.",
                "properties": {
                  "bankName": {
                    "type": "string"
                  },
                  "accountNumber": {
                    "type": "string"
                  },
                  "routingNumber": {
                    "type": "string"
                  }
                }
              },
              "lineItems": {
                "type": "array",
                "description": "Invoice line items. Match by lineNumber or description against PO lines.",
                "items": {
                  "type": "object",
                  "required": [
                    "description",
                    "quantity",
                    "unitPrice",
                    "totalPrice"
                  ],
                  "properties": {
                    "lineNumber": {
                      "type": "integer"
                    },
                    "description": {
                      "type": "string"
                    },
                    "quantity": {
                      "type": "number"
                    },
                    "unitPrice": {
                      "type": "number"
                    },
                    "totalPrice": {
                      "type": "number"
                    }
                  }
                }
              }
            }
          },
          "approvalThresholds": {
            "type": "object",
            "description": "Organizational approval thresholds and tolerance policies. Drives routing decisions in the BPMN gateway.",
            "properties": {
              "autoApproveLimit": {
                "type": "number",
                "description": "Maximum invoice total (in PO currency) that can be auto-approved without human review. Defaults to 1000 if not provided."
              },
              "managerApprovalLimit": {
                "type": "number",
                "description": "Invoices above this amount require manager-level approval. Defaults to 10000 if not provided."
              },
              "tolerancePercentage": {
                "type": "number",
                "description": "Acceptable variance % between PO and invoice amounts before triggering a discrepancy (e.g., 2 means 2%). Defaults to 2 if not provided."
              },
              "toleranceAmountFloor": {
                "type": "number",
                "description": "Minimum absolute amount difference that must also be exceeded for a variance to trigger discrepancy. Prevents noise from rounding. Defaults to 5."
              }
            }
          },
          "vendorContext": {
            "type": "object",
            "description": "Supplementary vendor history and risk context from ERP/CRM. Use to assess vendor reliability.",
            "properties": {
              "riskRating": {
                "type": "string",
                "description": "Vendor risk classification: LOW, MEDIUM, HIGH, BLOCKED."
              },
              "historicalDiscrepancyRate": {
                "type": "number",
                "description": "Percentage of past invoices from this vendor that had discrepancies (0-100)."
              },
              "onTimeDeliveryRate": {
                "type": "number",
                "description": "Percentage of past POs delivered on time (0-100)."
              },
              "isPreferredVendor": {
                "type": "boolean",
                "description": "True if vendor is on the approved/preferred vendor list."
              },
              "openDisputeCount": {
                "type": "integer",
                "description": "Number of currently open disputes with this vendor."
              }
            }
          },
          "processContext": {
            "type": "string",
            "description": "Optional free-text notes from upstream BPMN tasks or RPA robots (e.g., \u0027Invoice arrived 5 days late\u0027, \u0027GRN flagged partial delivery\u0027). Used for contextual reasoning."
          }
        },
        "definitions": {
          "job-attachment": {
            "type": "object",
            "required": [
              "ID"
            ],
            "x-uipath-resource-kind": "JobAttachment",
            "properties": {
              "ID": {
                "type": "string",
                "description": "Orchestrator attachment key"
              },
              "FullName": {
                "type": "string",
                "description": "File name"
              },
              "MimeType": {
                "type": "string",
                "description": "The MIME type of the content, such as \u0022application/json\u0022 or \u0022image/png\u0022"
              },
              "Metadata": {
                "type": "object",
                "description": "Dictionary\u003Cstring, string\u003E of metadata",
                "additionalProperties": {
                  "type": "string"
                }
              }
            }
          }
        }
      }

spec.outputArgumentsSchemaV2:
{
        "type": "object",
        "required": [
          "matchStatus",
          "recommendation",
          "confidenceScore",
          "nextBpmnGateway",
          "reconciliationSummary",
          "discrepancies",
          "actionItems",
          "reasoning"
        ],
        "properties": {
          "processInstanceId": {
            "type": "string",
            "description": "Echo back the processInstanceId from input for BPMN correlation. If not provided, generate a unique trace ID."
          },
          "matchStatus": {
            "type": "string",
            "description": "Result of the 3-way match (PO vs GRN vs Invoice). FULL_MATCH = all amounts and quantities align exactly. WITHIN_TOLERANCE = variance exists but is within the configured tolerance %. PARTIAL_MATCH = some lines match, others have discrepancies. MISMATCH = significant variance on amounts or quantities outside tolerance. CRITICAL_EXCEPTION = fraud indicators, blocked vendor, duplicate invoice, or missing critical document.",
            "enum": [
              "FULL_MATCH",
              "WITHIN_TOLERANCE",
              "PARTIAL_MATCH",
              "MISMATCH",
              "CRITICAL_EXCEPTION"
            ]
          },
          "recommendation": {
            "type": "string",
            "description": "Recommended next action to drive the BPMN exclusive gateway. AUTO_APPROVE = safe to post and schedule payment. RETURN_TO_VENDOR = send corrected invoice request to vendor. ESCALATE_TO_AP = route to AP team for manual review. ESCALATE_TO_MANAGER = route to budget owner or manager for approval. BLOCK_PAYMENT = halt process and trigger fraud/compliance review.",
            "enum": [
              "AUTO_APPROVE",
              "RETURN_TO_VENDOR",
              "ESCALATE_TO_AP",
              "ESCALATE_TO_MANAGER",
              "BLOCK_PAYMENT"
            ]
          },
          "confidenceScore": {
            "type": "number",
            "description": "Agent confidence in the recommendation, from 0 (no confidence) to 100 (certain). Scores below 60 should prompt human review regardless of recommendation."
          },
          "nextBpmnGateway": {
            "type": "string",
            "description": "The exact BPMN sequence flow label to activate at the exclusive gateway. Maps recommendation to a Maestro flow token (e.g., \u0027auto_approve_path\u0027, \u0027ap_review_path\u0027, \u0027manager_approval_path\u0027, \u0027vendor_dispute_path\u0027, \u0027fraud_hold_path\u0027)."
          },
          "reconciliationSummary": {
            "type": "object",
            "description": "High-level financial summary of the 3-way match result.",
            "required": [
              "poAmount",
              "invoiceAmount",
              "varianceAmount",
              "variancePercentage",
              "currency",
              "isWithinTolerance"
            ],
            "properties": {
              "poAmount": {
                "type": "number",
                "description": "Total PO amount (excl. tax) as reference baseline."
              },
              "grnAmount": {
                "type": "number",
                "description": "Total value of goods/services confirmed received via GRN. Null if GRN not provided."
              },
              "invoiceAmount": {
                "type": "number",
                "description": "Total invoice amount (excl. tax) as billed by vendor."
              },
              "varianceAmount": {
                "type": "number",
                "description": "Absolute difference between invoice total and PO total (invoiceAmount - poAmount)."
              },
              "variancePercentage": {
                "type": "number",
                "description": "Variance as a percentage of the PO amount. Positive = overbilled, negative = underbilled."
              },
              "currency": {
                "type": "string",
                "description": "Currency code for all amounts in this summary."
              },
              "isWithinTolerance": {
                "type": "boolean",
                "description": "True if variancePercentage is within the configured tolerancePercentage threshold."
              }
            }
          },
          "discrepancies": {
            "type": "array",
            "description": "List of specific discrepancies found during 3-way match. Empty array if FULL_MATCH.",
            "items": {
              "type": "object",
              "required": [
                "discrepancyId",
                "type",
                "severity",
                "description"
              ],
              "properties": {
                "discrepancyId": {
                  "type": "string",
                  "description": "Unique ID for this discrepancy (e.g., DISC-001)."
                },
                "type": {
                  "type": "string",
                  "description": "Category of discrepancy.",
                  "enum": [
                    "PRICE_VARIANCE",
                    "QUANTITY_VARIANCE",
                    "LINE_ITEM_MISSING",
                    "EXTRA_LINE_ITEM",
                    "CURRENCY_MISMATCH",
                    "VENDOR_MISMATCH",
                    "PO_REFERENCE_MISSING",
                    "DUPLICATE_INVOICE",
                    "BANK_DETAIL_CHANGE",
                    "TAX_DISCREPANCY",
                    "PAYMENT_TERMS_CONFLICT",
                    "GRN_NOT_RECEIVED"
                  ]
                },
                "severity": {
                  "type": "string",
                  "description": "Impact severity. CRITICAL discrepancies always trigger BLOCK_PAYMENT or ESCALATE.",
                  "enum": [
                    "LOW",
                    "MEDIUM",
                    "HIGH",
                    "CRITICAL"
                  ]
                },
                "lineNumber": {
                  "type": "integer",
                  "description": "PO line number where the discrepancy was found. Null for header-level discrepancies."
                },
                "description": {
                  "type": "string",
                  "description": "Human-readable description of the discrepancy (e.g., \u0027Invoice quantity 120 exceeds PO quantity 100 for line 3 - Widget A\u0027)."
                },
                "poValue": {
                  "type": "string",
                  "description": "The expected value from the PO."
                },
                "invoiceValue": {
                  "type": "string",
                  "description": "The actual value found on the invoice."
                },
                "impactAmount": {
                  "type": "number",
                  "description": "Financial impact of this discrepancy in PO currency. Positive = overbilled."
                }
              }
            }
          },
          "actionItems": {
            "type": "array",
            "description": "Ordered list of recommended actions for the next human or system actor in the BPMN process.",
            "items": {
              "type": "object",
              "required": [
                "actionId",
                "owner",
                "priority",
                "description"
              ],
              "properties": {
                "actionId": {
                  "type": "string",
                  "description": "Sequential action ID (e.g., ACT-001)."
                },
                "owner": {
                  "type": "string",
                  "description": "Who should perform this action: AP_TEAM, MANAGER, VENDOR, RPA_ROBOT, AGENT, SYSTEM."
                },
                "priority": {
                  "type": "string",
                  "description": "Action priority.",
                  "enum": [
                    "LOW",
                    "MEDIUM",
                    "HIGH",
                    "URGENT"
                  ]
                },
                "description": {
                  "type": "string",
                  "description": "Clear description of the action to take."
                },
                "dueDate": {
                  "type": "string",
                  "description": "Suggested due date for the action (YYYY-MM-DD). Omit if not applicable."
                }
              }
            }
          },
          "vendorCommunicationDraft": {
            "type": "string",
            "description": "Ready-to-send email draft addressed to the vendor when the recommendation is RETURN_TO_VENDOR. Includes specific discrepancy details, corrected figures, and instructions. Null if not applicable."
          },
          "fraudRiskIndicators": {
            "type": "array",
            "description": "List of fraud risk signals detected. Empty array if none found.",
            "items": {
              "type": "object",
              "properties": {
                "indicator": {
                  "type": "string",
                  "description": "Name of the fraud indicator (e.g., BANK_DETAIL_CHANGE, DUPLICATE_INVOICE, ROUND_NUMBER_INVOICE, VENDOR_NOT_IN_MASTER)."
                },
                "description": {
                  "type": "string",
                  "description": "Explanation of why this is flagged as a risk."
                },
                "riskLevel": {
                  "type": "string",
                  "description": "Risk level of this indicator.",
                  "enum": [
                    "LOW",
                    "MEDIUM",
                    "HIGH"
                  ]
                }
              }
            }
          },
          "reasoning": {
            "type": "string",
            "description": "Detailed step-by-step explanation of how the agent arrived at the matchStatus and recommendation. Include all comparisons made, tolerance checks, and decision logic. This is the audit trail for compliance."
          },
          "processingMetadata": {
            "type": "object",
            "description": "Technical metadata about this agent invocation.",
            "properties": {
              "agentVersion": {
                "type": "string",
                "description": "Agent version identifier."
              },
              "processedAt": {
                "type": "string",
                "description": "ISO 8601 timestamp of when this analysis was completed."
              },
              "documentsProcessed": {
                "type": "array",
                "description": "List of document types processed: PO, GRN, INVOICE.",
                "items": {
                  "type": "string"
                }
              },
              "toleranceApplied": {
                "type": "number",
                "description": "The tolerance percentage that was applied in this run."
              }
            }
          }
        }
      }

